1846 bool VectorCombine::foldShuffleOfShuffles(Instruction &I) {
1847   ArrayRef<int> OuterMask;
1848   Value *OuterV0, *OuterV1;
1849   if (!match(&I,
1850              m_Shuffle(m_Value(OuterV0), m_Value(OuterV1), m_Mask(OuterMask))))
1851     return false;
1852 
1853   ArrayRef<int> InnerMask0, InnerMask1;
1854   Value *V0 = nullptr, *V1 = nullptr;
1855   UndefValue *U0 = nullptr, *U1 = nullptr;
1856   bool Match0 = match(
1857       OuterV0, m_Shuffle(m_Value(V0), m_UndefValue(U0), m_Mask(InnerMask0)));
1858   bool Match1 = match(
1859       OuterV1, m_Shuffle(m_Value(V1), m_UndefValue(U1), m_Mask(InnerMask1)));
1860   if (!Match0 && !Match1)
1861     return false;
1862 
1863   V0 = Match0 ? V0 : OuterV0;
1864   V1 = Match1 ? V1 : OuterV1;
1865   auto *ShuffleDstTy = dyn_cast<FixedVectorType>(I.getType());
1866   auto *ShuffleSrcTy = dyn_cast<FixedVectorType>(V0->getType());
1867   auto *ShuffleImmTy = dyn_cast<FixedVectorType>(I.getOperand(0)->getType());
1868   if (!ShuffleDstTy || !ShuffleSrcTy || !ShuffleImmTy ||
1869       V0->getType() != V1->getType())
1870     return false;
1871 
1872   unsigned NumSrcElts = ShuffleSrcTy->getNumElements();
1873   unsigned NumImmElts = ShuffleImmTy->getNumElements();
1874 
1875   // Bail if either inner masks reference a RHS undef arg.
1876   if ((Match0 && !isa<PoisonValue>(U0) &&
1877        any_of(InnerMask0, [&](int M) { return M >= (int)NumSrcElts; })) ||
1878       (Match1 && !isa<PoisonValue>(U1) &&
1879        any_of(InnerMask1, [&](int M) { return M >= (int)NumSrcElts; })))
1880     return false;
1881 
1882   // Merge shuffles - replace index to the RHS poison arg with PoisonMaskElem,
1883   SmallVector<int, 16> NewMask(OuterMask);
1884   for (int &M : NewMask) {
1885     if (0 <= M && M < (int)NumImmElts) {
1886       if (Match0)
1887         M = (InnerMask0[M] >= (int)NumSrcElts) ? PoisonMaskElem : InnerMask0[M];
1888     } else if (M >= (int)NumImmElts) {
1889       if (Match1) {
1890         if (InnerMask1[M - NumImmElts] >= (int)NumSrcElts)
1891           M = PoisonMaskElem;
1892         else
1893           M = InnerMask1[M - NumImmElts] + (V0 == V1 ? 0 : NumSrcElts);
1894       }
1895     }
1896   }
1897 
1898   // Have we folded to an Identity shuffle?
1899   if (ShuffleVectorInst::isIdentityMask(NewMask, NumSrcElts)) {
1900     replaceValue(I, *V0);
1901     return true;
1902   }
1903 
1904   // Try to merge the shuffles if the new shuffle is not costly.
1905   InstructionCost InnerCost0 = 0;
1906   if (Match0)
1907     InnerCost0 = TTI.getShuffleCost(
1908         TargetTransformInfo::SK_PermuteSingleSrc, ShuffleSrcTy, InnerMask0,
1909         CostKind, 0, nullptr, {V0, U0}, cast<ShuffleVectorInst>(OuterV0));
1910 
1911   InstructionCost InnerCost1 = 0;
1912   if (Match1)
1913     InnerCost1 = TTI.getShuffleCost(
1914         TargetTransformInfo::SK_PermuteSingleSrc, ShuffleSrcTy, InnerMask1,
1915         CostKind, 0, nullptr, {V1, U1}, cast<ShuffleVectorInst>(OuterV1));
1916 
1917   InstructionCost OuterCost = TTI.getShuffleCost(
1918       TargetTransformInfo::SK_PermuteTwoSrc, ShuffleImmTy, OuterMask, CostKind,
1919       0, nullptr, {OuterV0, OuterV1}, &I);
1920 
1921   InstructionCost OldCost = InnerCost0 + InnerCost1 + OuterCost;
1922 
1923   InstructionCost NewCost =
1924       TTI.getShuffleCost(TargetTransformInfo::SK_PermuteTwoSrc, ShuffleSrcTy,
1925                          NewMask, CostKind, 0, nullptr, {V0, V1});
1926   if (!OuterV0->hasOneUse())
1927     NewCost += InnerCost0;
1928   if (!OuterV1->hasOneUse())
1929     NewCost += InnerCost1;
1930 
1931   LLVM_DEBUG(dbgs() << "Found a shuffle feeding two shuffles: " << I
1932                     << "\n  OldCost: " << OldCost << " vs NewCost: " << NewCost
1933                     << "\n");
1934   if (NewCost > OldCost)
1935     return false;
1936 
1937   // Clear unused sources to poison.
1938   if (none_of(NewMask, [&](int M) { return 0 <= M && M < (int)NumSrcElts; }))
1939     V0 = PoisonValue::get(ShuffleSrcTy);
1940   if (none_of(NewMask, [&](int M) { return (int)NumSrcElts <= M; }))
1941     V1 = PoisonValue::get(ShuffleSrcTy);
1942 
1943   Value *Shuf = Builder.CreateShuffleVector(V0, V1, NewMask);
1944   replaceValue(I, *Shuf);
1945   return true;
1946 }
